// CF02 WF_SEO_SCORE — fetch topics + project context.
// Input: { project_id, force?: boolean }

const input = $input.first().json;
const projectId = input.project_id;
const force = input.force === true;

if (!projectId) {
  throw new Error('WF_SEO_SCORE requires { project_id } in trigger payload');
}

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

let topicsUrl = `${supabaseUrl}/rest/v1/topics?project_id=eq.${projectId}&select=id,seo_title,original_title,narrative_hook,topic_number&order=topic_number.asc`;
if (!force) topicsUrl += '&seo_scored_at=is.null';

const topicsRes = await fetch(topicsUrl, { method: 'GET', headers: sbHeaders });
if (!topicsRes.ok) {
  throw new Error(`Fetch topics failed: HTTP ${topicsRes.status}: ${await topicsRes.text()}`);
}
const topics = await topicsRes.json();

const projUrl = `${supabaseUrl}/rest/v1/projects?id=eq.${projectId}&select=niche,niche_description,niche_expertise_profile`;
const projRes = await fetch(projUrl, { method: 'GET', headers: sbHeaders });
if (!projRes.ok) {
  throw new Error(`Fetch project failed: HTTP ${projRes.status}: ${await projRes.text()}`);
}
const projArr = await projRes.json();
const project = projArr[0] || {};

return [{
  json: {
    project_id: projectId,
    force,
    topics,
    topic_count: topics.length,
    niche: project.niche || '',
    niche_description: project.niche_description || ''
  }
}];

const data = $input.first().json;
const topics = data.topics || [];
const BATCH_SIZE = 5;

const items = [];
for (let i = 0; i < topics.length; i += BATCH_SIZE) {
  items.push({
    json: {
      project_id: data.project_id,
      niche: data.niche,
      niche_description: data.niche_description,
      batch_index: Math.floor(i / BATCH_SIZE),
      batch: topics.slice(i, i + BATCH_SIZE),
      total_batches: Math.ceil(topics.length / BATCH_SIZE),
      total_topics: topics.length
    }
  });
}

if (items.length === 0) {
  return [{
    json: {
      project_id: data.project_id,
      skipped: true,
      reason: 'No topics pending SEO scoring (pass force=true to rescore)',
      total_topics: 0
    }
  }];
}

return items;

// CF02 per-batch SEO scorer.
// Steps per topic:
//  1. Claude Opus generates 3 keyword variants (exact/broad/narrow)
//  2. YouTube autocomplete for each variant
//  3. YouTube search.list for primary keyword (totalResults + videoIds)
//  4. YouTube videos.list for top10 avg views
//  5. Claude Opus produces final seo_score + classification + summary
//  6. PATCH topic + production_logs

const data = $input.item.json;
if (data.skipped) return $input.item;

const batch = data.batch || [];
const projectId = data.project_id;
const niche = data.niche;
const nicheDesc = data.niche_description || niche;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};
const ytKey = $env.YOUTUBE_API_KEY;
const anthropicKey = $env.ANTHROPIC_API_KEY;

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

let quotaExhausted = false;

async function fetchWithRetry(url, options, label, maxRetries = 4) {
  let lastErr = null;
  let lastStatus = 0;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);
      lastStatus = res.status;
      if (res.ok) {
        return { ok: true, json: await res.json(), status: res.status, attempts: attempt };
      }
      const body = await res.text();
      if (res.status === 403 && /quotaExceeded|dailyLimitExceeded/i.test(body)) {
        return { ok: false, quota: true, status: res.status, error: body, attempts: attempt };
      }
      if (res.status >= 400 && res.status < 500 && res.status !== 429) {
        return { ok: false, status: res.status, error: body, attempts: attempt };
      }
      lastErr = new Error(`HTTP ${res.status}: ${body.slice(0, 300)}`);
    } catch (e) {
      lastErr = e;
    }
    if (attempt < maxRetries) {
      const delay = Math.min(1000 * Math.pow(2, attempt - 1), 30000);
      await sleep(delay);
    }
  }
  return { ok: false, status: lastStatus, error: lastErr?.message || `${label} failed`, attempts: maxRetries };
}

// Tolerant autocomplete fetcher: one inline retry, parse suggestqueries response.
async function autocomplete(q) {
  const url = `https://suggestqueries.google.com/complete/search?client=firefox&ds=yt&q=${encodeURIComponent(q)}`;
  for (let attempt = 1; attempt <= 2; attempt++) {
    try {
      const res = await fetch(url, { method: 'GET' });
      if (res.ok) {
        const txt = await res.text();
        try {
          const parsed = JSON.parse(txt);
          // response shape: [query, [suggestions...], ...]
          const arr = Array.isArray(parsed?.[1]) ? parsed[1] : [];
          return { ok: true, suggestions: arr, count: arr.length };
        } catch {
          return { ok: true, suggestions: [], count: 0 };
        }
      }
    } catch { /* retry once */ }
    if (attempt === 1) await sleep(500);
  }
  return { ok: false, suggestions: [], count: 0 };
}

async function logProduction(topicId, action, status, durationMs, costUsd, retryCount) {
  try {
    await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: projectId,
        topic_id: topicId,
        stage: 'seo_score',
        scene_number: null,
        action,
        status,
        duration_ms: durationMs,
        cost_usd: costUsd,
        retry_count: retryCount
      })
    });
  } catch (_) { }
}

function extractPrimaryKeyword(title) {
  if (!title) return '';
  // strip common clickbait wrappers + take first 6 words
  return title
    .replace(/["'“”‘’]/g, '')
    .replace(/[:\-\|].*$/, '')
    .trim()
    .split(/\s+/)
    .slice(0, 6)
    .join(' ')
    .toLowerCase();
}

function fallbackPayload(title, reason) {
  return {
    seo_score: 50,
    seo_classification: null,
    primary_keyword: extractPrimaryKeyword(title),
    keyword_variants: [],
    search_volume_proxy: null,
    competition_level: null,
    seo_opportunity_summary: reason,
    seo_scored_at: new Date().toISOString()
  };
}

async function callOpus(userPrompt, maxTokens, label) {
  return fetchWithRetry('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'x-api-key': anthropicKey,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    },
    body: JSON.stringify({
      model: 'claude-opus-4-6',
      max_tokens: maxTokens,
      messages: [{ role: 'user', content: userPrompt }]
    })
  }, label);
}

function parseJsonLoose(text) {
  if (!text) return null;
  const clean = text.replace(/```json|```/g, '').trim();
  try { return JSON.parse(clean); } catch { }
  const m = clean.match(/\{[\s\S]*\}/);
  if (m) { try { return JSON.parse(m[0]); } catch { } }
  return null;
}

const batchResults = [];

for (const topic of batch) {
  const topicStart = Date.now();
  let retryCount = 0;
  const title = topic.seo_title || topic.original_title || '';

  if (!title) {
    batchResults.push({ topic_id: topic.id, patch: fallbackPayload('', 'Missing topic title') });
    continue;
  }

  // --- 1. Generate 3 keyword variants via Opus ---
  const variantPrompt = `Given topic "${title}" in niche "${nicheDesc}", produce 3 keyword variants: exact (topic as-is), broad (parent concept), narrow (specific sub-angle). Return JSON: {"exact": "…", "broad": "…", "narrow": "…"}. No other text.`;
  const variantStart = Date.now();
  const variantRes = await callOpus(variantPrompt, 200, 'claude_opus_variants');
  retryCount += (variantRes.attempts || 1) - 1;

  let variants = { exact: extractPrimaryKeyword(title), broad: niche || '', narrow: '' };
  if (variantRes.ok) {
    const parsed = parseJsonLoose(variantRes.json?.content?.[0]?.text || '');
    if (parsed && (parsed.exact || parsed.broad || parsed.narrow)) {
      variants = {
        exact: String(parsed.exact || variants.exact).slice(0, 200),
        broad: String(parsed.broad || variants.broad).slice(0, 200),
        narrow: String(parsed.narrow || variants.narrow).slice(0, 200)
      };
    }
    await logProduction(topic.id, 'claude_opus_variants', 'success', Date.now() - variantStart, 0.004, retryCount);
  } else {
    await logProduction(topic.id, 'claude_opus_variants', 'error', Date.now() - variantStart, 0, retryCount);
  }

  const variantArr = [variants.exact, variants.broad, variants.narrow].filter(v => v && v.trim().length);

  // --- 2. Autocomplete per variant (200ms delay between) ---
  const autocompleteCounts = [];
  for (let i = 0; i < variantArr.length; i++) {
    const ac = await autocomplete(variantArr[i]);
    autocompleteCounts.push(ac.count || 0);
    if (i < variantArr.length - 1) await sleep(200);
  }
  while (autocompleteCounts.length < 3) autocompleteCounts.push(0);

  if (quotaExhausted) {
    batchResults.push({ topic_id: topic.id, patch: fallbackPayload(title, 'YouTube quota exhausted during this run') });
    continue;
  }

  // --- 3. YouTube search.list for primary keyword ---
  const primary = variants.exact || extractPrimaryKeyword(title);
  const searchUrl = `https://www.googleapis.com/youtube/v3/search?part=snippet&q=${encodeURIComponent(primary)}&type=video&maxResults=10&key=${ytKey}`;
  const searchRes = await fetchWithRetry(searchUrl, { method: 'GET' }, 'yt_search_seo');
  retryCount += (searchRes.attempts || 1) - 1;

  if (searchRes.quota) {
    quotaExhausted = true;
    batchResults.push({ topic_id: topic.id, patch: fallbackPayload(title, 'YouTube quota exceeded (403)') });
    await logProduction(topic.id, 'yt_search_seo', 'quota_exceeded', Date.now() - topicStart, 0, retryCount);
    continue;
  }

  const totalResults = searchRes.ok ? (searchRes.json?.pageInfo?.totalResults || 0) : 0;
  const videoIds = searchRes.ok ? (searchRes.json?.items || []).map(i => i.id?.videoId).filter(Boolean) : [];

  // --- 4. videos.list for top10 stats ---
  let top10AvgViews = 0;
  let topResultPublished = null;
  if (videoIds.length > 0) {
    const vUrl = `https://www.googleapis.com/youtube/v3/videos?part=statistics,snippet&id=${videoIds.join(',')}&key=${ytKey}`;
    const vRes = await fetchWithRetry(vUrl, { method: 'GET' }, 'yt_videos_seo');
    retryCount += (vRes.attempts || 1) - 1;
    if (vRes.quota) quotaExhausted = true;
    if (vRes.ok) {
      const items = vRes.json?.items || [];
      const views = items.map(v => parseInt(v.statistics?.viewCount || '0', 10)).filter(v => v > 0);
      top10AvgViews = views.length ? Math.round(views.reduce((a, b) => a + b, 0) / views.length) : 0;
      topResultPublished = items[0]?.snippet?.publishedAt || null;
    }
  }

  // --- 5. Claude Opus scoring call ---
  const userPrompt = `SEO OPPORTUNITY ANALYSIS

Topic: ${title}
Niche: ${nicheDesc}
Primary Keyword: ${primary}
Keyword Variants Generated: ${JSON.stringify(variantArr)}

AUTOCOMPLETE DATA:
Keyword 1 (${variantArr[0] || ''}): ${autocompleteCounts[0]} suggestions returned
Keyword 2 (${variantArr[1] || ''}): ${autocompleteCounts[1]} suggestions returned
Keyword 3 (${variantArr[2] || ''}): ${autocompleteCounts[2]} suggestions returned

COMPETITION DATA:
YouTube search results for "${primary}": ${totalResults} videos
Estimated top 10 videos average views: ${top10AvgViews}
Top result published: ${topResultPublished || 'unknown'}

Scoring logic:
  autocomplete_demand_score:
    0 suggestions: 0
    1-2: 20, 3-4: 45, 5-6: 65, 7-8: 85, 8+: 100
  search_volume_proxy = avg(autocomplete_count_1, count_2, count_3) * 12.5
  competition_inverse_score:
    >500K: 0, 100K-500K: 15, 50K-100K: 35, 10K-50K: 55, 5K-10K: 70, 1K-5K: 85, <1K: 95
  seo_score = (autocomplete_demand * 0.40) + (min(search_volume_proxy, 100) * 0.30) + (competition_inverse * 0.30)

Classification rules:
  blue-ocean: totalResults < 5,000 AND autocomplete suggestions > 4
  competitive: totalResults 5K-100K
  red-ocean: totalResults > 100K
  dead-sea: totalResults < 1,000 AND autocomplete suggestions < 2

Return ONLY this JSON:
{
  "seo_score": <integer 0-100>,
  "seo_classification": "<blue-ocean|competitive|red-ocean|dead-sea>",
  "primary_keyword": "<string>",
  "keyword_variants": ["<string>", "<string>", "<string>"],
  "search_demand_signal": "<high|medium|low|none>",
  "competition_level": "<low|medium|high>",
  "search_volume_proxy": <integer>,
  "opportunity_summary": "<string, 1 sentence, be specific about numbers>"
}`;

  const scoreStart = Date.now();
  const scoreRes = await callOpus(userPrompt, 600, 'claude_opus_seo');
  retryCount += (scoreRes.attempts || 1) - 1;

  let patch;
  if (!scoreRes.ok) {
    patch = fallbackPayload(title, `Claude SEO call failed: ${scoreRes.error?.slice(0, 120) || 'unknown'}`);
    await logProduction(topic.id, 'claude_opus_seo', 'error', Date.now() - scoreStart, 0, retryCount);
  } else {
    const parsed = parseJsonLoose(scoreRes.json?.content?.[0]?.text || '');
    if (!parsed || typeof parsed.seo_score !== 'number') {
      patch = fallbackPayload(title, 'Claude SEO response failed to parse');
      await logProduction(topic.id, 'claude_opus_seo', 'parse_error', Date.now() - scoreStart, 0.012, retryCount);
    } else {
      const classification = ['blue-ocean', 'competitive', 'red-ocean', 'dead-sea'].includes(parsed.seo_classification)
        ? parsed.seo_classification
        : null;
      const compLevel = ['low', 'medium', 'high'].includes(parsed.competition_level) ? parsed.competition_level : null;
      const kv = Array.isArray(parsed.keyword_variants)
        ? parsed.keyword_variants.slice(0, 10).map(v => String(v).slice(0, 200))
        : variantArr;
      patch = {
        seo_score: Math.max(0, Math.min(100, Math.round(parsed.seo_score))),
        seo_classification: classification,
        primary_keyword: String(parsed.primary_keyword || primary).slice(0, 200),
        keyword_variants: kv,
        search_volume_proxy: parsed.search_volume_proxy != null ? parseInt(parsed.search_volume_proxy, 10) : null,
        competition_level: compLevel,
        seo_opportunity_summary: String(parsed.opportunity_summary || '').slice(0, 2000),
        seo_scored_at: new Date().toISOString()
      };
      await logProduction(topic.id, 'claude_opus_seo', 'success', Date.now() - scoreStart, 0.014, retryCount);
    }
  }

  batchResults.push({ topic_id: topic.id, patch });
}

// PATCH all topics
for (const r of batchResults) {
  try {
    const patchRes = await fetch(`${supabaseUrl}/rest/v1/topics?id=eq.${r.topic_id}`, {
      method: 'PATCH',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify(r.patch)
    });
    if (!patchRes.ok) {
      const t = await patchRes.text();
      r.patch_error = `HTTP ${patchRes.status}: ${t.slice(0, 200)}`;
    }
  } catch (e) {
    r.patch_error = e.message;
  }
}

if (data.batch_index + 1 < data.total_batches) {
  await sleep(2000);
}

return {
  json: {
    project_id: projectId,
    batch_index: data.batch_index,
    total_batches: data.total_batches,
    scored: batchResults.length,
    quota_exhausted: quotaExhausted,
    results: batchResults
  }
};

const items = $input.all().map(i => i.json).filter(j => !j.skipped);
if (items.length === 0) {
  return [{ json: { success: true, scored_total: 0, message: 'No topics needed SEO scoring' } }];
}

const totalScored = items.reduce((s, b) => s + (b.scored || 0), 0);
const quota = items.some(b => b.quota_exhausted);
const projectId = items[0]?.project_id;

return [{
  json: {
    success: true,
    project_id: projectId,
    scored_total: totalScored,
    batches_processed: items.length,
    quota_exhausted: quota,
    finished_at: new Date().toISOString()
  }
}];
